cat > validators/validate_text_locale_fr.py <<'PY'
# description : refuse tout texte qui n'est pas {"FR": "..."} ou liste de dicts {"FR": "..."}.
# howto : ok, diags = validate_text_locale_fr(obj)
def _is_fr_text(v):
    return isinstance(v, dict) and set(v.keys())=={"FR"} and isinstance(v["FR"], str)

def _walk(obj, path="$"):
    if isinstance(obj, dict):
        for k,v in obj.items():
            for p,vv in _walk(v, f"{path}.{k}"): yield p,vv
    elif isinstance(obj, list):
        for i,v in enumerate(obj):
            for p,vv in _walk(v, f"{path}[{i}]"): yield p,vv
    else:
        yield path, obj

def validate_text_locale_fr(obj):
    diags = []
    for p,v in _walk(obj):
        # heuristique : si c'est une string et que la clé parent pourrait être textuelle, on impose le format
        if isinstance(v, str):
            diags.append({"check":"TEXT_FR","path":p,"severity":"error","message":{"FR":"Texte brut interdit, attendu {\"FR\":\"...\"}."}})
        elif isinstance(v, list) and any(isinstance(x, str) for x in v):
            diags.append({"check":"TEXT_FR","path":p,"severity":"error","message":{"FR":"Liste de strings interdite, utiliser des objets {\"FR\":\"...\"}."}})
        elif isinstance(v, dict) and any(isinstance(x, str) for x in v.values()) and not _is_fr_text(v):
            # cas: dict de strings => non conforme
            diags.append({"check":"TEXT_FR","path":p,"severity":"error","message":{"FR":"Dictionnaire texte non localisé FR."}})
    ok = len(diags)==0
    return ok, diags
PY

cat > validators/validate_secretref.py <<'PY'
# description : valide qu'aucun secret en clair n'est présent et que les secretref ont le bon shape.
# howto : ok, diags = validate_secretref(obj)
SAFE_KEYS = {"provider","path","version","format"}

def _walk(obj, path="$"):
    if isinstance(obj, dict):
        for k,v in obj.items():
            yield from _walk(v, f"{path}.{k}")
    elif isinstance(obj, list):
        for i,v in enumerate(obj):
            yield from _walk(v, f"{path}[{i}]")
    else:
        yield path, obj

def _looks_like_secret_key(path):
    low = path.lower()
    return any(t in low for t in ["api_key","apikey","secret","token","password","pwd"])

def validate_secretref(obj):
    diags=[]
    for p,v in _walk(obj):
        if _looks_like_secret_key(p):
            diags.append({"check":"SECRET_CLEAR","path":p,"severity":"error","message":{"FR":"Secret potentiellement en clair détecté."}})
        if isinstance(v, dict) and v.keys() & {"provider","path"}:
            extra = set(v.keys()) - SAFE_KEYS
            missing = {"provider","path"} - set(v.keys())
            if missing or extra:
                diags.append({"check":"SECRETREF_SHAPE","path":p,"severity":"error",
                              "message":{"FR":f"secretref invalide (manque: {sorted(missing)}, extra: {sorted(extra)})"}})
    ok = len(diags)==0
    return ok, diags
PY

# --- generate_schema_any (GET/EXECUTE/VALIDATE/RENDER) ---
cat > runner/run_generate_schema_any.py <<'PY'
# description : Orchestrateur "generate_schema_any" (GET→EXECUTE→VALIDATE→RENDER), pur, sans IO.
# howto : from runner.run_generate_schema_any import run_generate_schema_any
from importlib import import_module
from log.log_event import log_event
from log.register_version import register_version

def run_generate_schema_any(method_obj, scenario_obj, vectors):
    method_ident = (method_obj.get("identity") or {}).get("ident","generate_schema_any")
    def _load(m,f): return import_module(m).__dict__[f]
    try:
        get = _load("scenarios.generate_schema_any_get","get_step")
        exe = _load("scenarios.generate_schema_any_execute","execute_step")
        val = _load("scenarios.generate_schema_any_validate","validate_step")
        ren = _load("scenarios.generate_schema_any_render","render_step")

        spec = get(vectors)
        if not spec.get("ok"): raise RuntimeError("GET failed: " + "; ".join((spec.get("diagnostics") or [])))
        result = exe(spec)
        if not result.get("ok"): raise RuntimeError("EXECUTE failed")
        normalized = val(result)
        if not normalized.get("ok"): raise RuntimeError("VALIDATE failed")
        rendered = ren(normalized, spec)

        log_event({"ident":"generate_schema_any_summary","status":"ok","method":method_ident})
        register_version("generate_schema_any",(method_obj.get("rules") or {}).get("version","0.1.0"),{"status":"success"})
        return {"ok": True, "schema": rendered.get("schema")}
    except Exception as e:
        log_event({"ident":"generate_schema_any_summary","status":"failed","error":str(e)})
        register_version("generate_schema_any","0.1.0",{"status":"failure","error":str(e)})
        return {"ok": False, "error": str(e)}
PY

cat > scenarios/generate_schema_any_get.py <<'PY'
# description : GET — vérifie input vectors et prépare la spec (objet + hints/policy normalisés).
# howto : from scenarios.generate_schema_any_get import get_step
from log.log_event import log_event
from validators.validate_ivc_dro import validate_ivc_dro

def get_step(vectors):
    obj = vectors.get("object")
    ok_ivc, diag_ivc = validate_ivc_dro(obj) if isinstance(obj, dict) else (False, ["object must be dict"])
    spec = {"object": obj, "hints": vectors.get("hints") or {}, "policy": vectors.get("policy") or {}}
    diags = [] + (diag_ivc if not ok_ivc else [])
    log_event({"kind":"step","step":"GET","method":"generate_schema_any","ok": ok_ivc, "diagnostics": diags})
    return {"ok": ok_ivc, "object": obj, "hints": spec["hints"], "policy": spec["policy"], "diagnostics": diags}
PY

cat > scenarios/generate_schema_any_execute.py <<'PY'
# description : EXECUTE — infère une structure simple (types) et prépare constraints vides.
# howto : from scenarios.generate_schema_any_execute import execute_step
from log.log_event import log_event

def _type_name(v):
    if v is None: return "null"
    if isinstance(v,bool): return "bool"
    if isinstance(v,int): return "int"
    if isinstance(v,float): return "float"
    if isinstance(v,str): return "str"
    if isinstance(v,list): return "list"
    if isinstance(v,dict): return "dict"
    return type(v).__name__

def _infer_structure(v):
    if isinstance(v, dict):
        return {k: _infer_structure(vv) for k,vv in v.items()}
    if isinstance(v, list):
        return {"type": "list", "items": _infer_structure(v[0]) if v else {"type":"any"}}
    return {"type": _type_name(v)}

def execute_step(spec):
    obj = spec.get("object") or {}
    struct = _infer_structure(obj)
    schema = {
        "identity": {"ident": f"schema_for::{(obj.get('identity') or {}).get('ident','unknown')}"},
        "view": {},
        "context": {"relations": {"for_object": (obj.get("identity") or {}).get("ident")}},
        "definitions": {"structure": struct, "constraints": {}},
        "rules": {"status": "draft", "version": "0.1.0"},
        "options": {"allow_extra_fields": False}
    }
    log_event({"kind":"step","step":"EXECUTE","method":"generate_schema_any"})
    return {"ok": True, "schema": schema}
PY

