cat > runner/run_validate_any.py <<'PY'
# description : Orchestrateur "validate_any" (GET→EXECUTE→VALIDATE→RENDER) + hooks validate.
# howto : from runner.run_validate_any import run_validate_any
from importlib import import_module
from log.log_event import log_event
from log.register_version import register_version

def run_validate_any(method_obj, scenario_obj, vectors):
    method_ident = (method_obj.get("identity") or {}).get("ident","validate_any")
    def _load(m,f): return import_module(m).__dict__[f]
    hooks = (method_obj.get("definitions") or {}).get("hooks") or {}
    try:
        if "before" in hooks:
            _load("hooks.hook_before_validate","hook_before_validate")({"method":method_ident,"vectors":vectors})

        get = _load("scenarios.validate_any_get","get_step")
        exe = _load("scenarios.validate_any_execute","execute_step")
        val = _load("scenarios.validate_any_validate","validate_step")
        ren = _load("scenarios.validate_any_render","render_step")

        spec = get(vectors)
        if not spec.get("ok"): raise RuntimeError("GET failed: " + "; ".join(spec.get("diagnostics") or []))
        result = exe(spec)
        if not result.get("ok"): raise RuntimeError("EXECUTE failed")
        normalized = val(result)
        if not normalized.get("ok"): raise RuntimeError("VALIDATE failed")
        rendered = ren(normalized, spec)

        if "after" in hooks:
            _load("hooks.hook_after_validate","hook_after_validate")({"method":method_ident,"vectors":vectors})

        log_event({"ident":"validate_any_summary","status":"ok","method":method_ident})
        register_version("validate_any",(method_obj.get("rules") or {}).get("version","0.1.0"),{"status":"success"})
        return {"ok": True, "report": rendered.get("report")}
    except Exception as e:
        if "onfailure" in hooks:
            _load("hooks.hook_onfailure_validate","hook_onfailure_validate")({"method":method_ident,"error":str(e),"vectors":vectors})
        log_event({"ident":"validate_any_summary","status":"failed","error":str(e)})
        register_version("validate_any","0.1.0",{"status":"failure","error":str(e)})
