# description : n'impose {"FR": "..."} QUE sur les champs textuels (name/title/description/summary/label et definitions.fields.*)
# howto : ok, diags = validate_text_locale_fr(obj)

TEXT_KEYS = {"name","title","description","summary","label"}

def _walk(obj, path="$"):
    if isinstance(obj, dict):
        for k,v in obj.items():
            yield from _walk(v, f"{path}.{k}")
    elif isinstance(obj, list):
        for i,v in enumerate(obj):
            yield from _walk(v, f"{path}[{i}]")
    else:
        yield path, obj

def _is_fr_text_block(v):
    return isinstance(v, dict) and set(v.keys())=={"FR"} and isinstance(v["FR"], str)

def _is_textual_path(path: str) -> bool:
    # impose la localisation FR pour:
    # - ....<name|title|description|summary|label>
    # - ...definitions.fields...  (contenus éditoriaux)
    if path.endswith(".name") or path.endswith(".title") or path.endswith(".description") or path.endswith(".summary") or path.endswith(".label"):
