    # on parcourt uniquement les noeuds dict/list pour vérifier les blocs textuels
    def _walk_nodes(o, path="$"):
        if isinstance(o, dict):
            # si ce noeud est textuel -> il doit être {"FR": "..."}
            if _is_textual_path(path):
                if not _is_fr_text_block(o):
                    diags.append({"check":"TEXT_FR","path":path,"severity":"error","message":{"FR":"Bloc textuel non localisé. Attendu {\"FR\":\"...\"}."}})
            for k,v in o.items():
                _walk_nodes(v, f"{path}.{k}")
        elif isinstance(o, list):
            for i,v in enumerate(o):
                _walk_nodes(v, f"{path}[{i}]")
        else:
            # valeur scalaire : on n'impose rien ici (sauf si le parent était textuel, ce qui est géré au niveau dict)
            pass

    _walk_nodes(obj, "$")
    ok = len([d for d in diags if d.get("severity")=="error"])==0
    return ok, diags
