# howto : from bootstrap.execute_plan_execute import execute_step
from metameta.dispatch_action_execute import execute_action
from log.log_event import log_event
def execute_step(spec):
    plan = list(spec.get("plan") or [])
    results = []
    if spec.get("policy",{}).get("execute_actions") is True:
        for a in plan:
            # on encode l'action sous forme d'une pseudo-ref crochet
            call = a.get("action","noop")
            args = []
            if "path" in a: args.append(a["path"])
            if "kind" in a: args.append(a["kind"])
            ref = {"call": call, "args": args}
            results.append(execute_action({"path":"$.bootstrap.plan","ref":ref}, spec.get("agent")))
    else:
        log_event({"ident":"bootstrap_execute_plan","status":"skipped","reason":"dry_run"})
    return {"ok": True, "results": results}
