# ---------- RUNNER (orchestrateur bootstrap) ----------
cat > runner/run_bootstrap.py <<'PY'
# description : Orchestrateur "bootstrap" (chaîne les 7 étapes, chaque étape en 4 phases)
# howto : from runner.run_bootstrap import run_bootstrap
from importlib import import_module
from log.log_event import log_event
from log.register_version import register_version

def _L(m,f): return import_module(m).__dict__[f]

def _run_step(mod, vectors, with_policy=None):
    get = _L(f"bootstrap.{mod}_get","get_step")
    exe = _L(f"bootstrap.{mod}_execute","execute_step")
    val = _L(f"bootstrap.{mod}_validate","validate_step")
    ren = _L(f"bootstrap.{mod}_render","render_step")
    spec = get(vectors)
    result = exe(spec)
    validated = val(result)
    rendered = ren(validated, spec)
    return {"spec": spec, "result": result, "validated": validated, "rendered": rendered}

def run_bootstrap(method_obj, scenario_obj, vectors):
    hooks = (method_obj.get("definitions") or {}).get("hooks") or []
    agent = vectors.get("agent")

    try:
        if "before" in hooks:
            _L("hooks.hook_before_bootstrap","hook_before_bootstrap")({"agent": agent})

        # 1) resolve_config
        s1 = _run_step("resolve_config", {"config": vectors.get("config"), "agent": agent, "policy": vectors.get("policy")})
        cfg = s1["rendered"]["config"]

        # 2) prepare_env
        s2 = _run_step("prepare_env", {"config": cfg})
        prepare_plan = s2["rendered"]["plan"]

        # 3) generate_catalogs
        s3 = _run_step("generate_catalogs", {"config": cfg})

        # 4) materialize_templates
        s4 = _run_step("materialize_templates", {"config": cfg})
        tpl_plan = s4["rendered"]["plan"]

        # 5) wire_integrations
        s5 = _run_step("wire_integrations", {"config": cfg})
        integ_plan = s5["rendered"]["plan"]

        # 6) execute_plan (optionnel)
        s6 = _run_step("execute_plan", {
            "prepare_env_plan": prepare_plan,
            "templates_plan": tpl_plan,
            "integrations_plan": integ_plan,
            "policy": (cfg.get("policies") or {}),
            "agent": agent
        })

        # 7) finalize (manifest)
        s7 = _run_step("finalize", {
            "parts": {
                "resolve_config": s1["rendered"]["report"],
                "prepare_env": s2["rendered"]["report"],
                "generate_catalogs": s3["rendered"]["report"],
                "materialize_templates": s4["rendered"]["report"],
                "wire_integrations": s5["rendered"]["report"],
                "execute_plan": s6["rendered"]["report"]
            }
        })

        if "after" in hooks:
            _L("hooks.hook_after_bootstrap","hook_after_bootstrap")({"agent": agent})

        log_event({"ident":"bootstrap_summary","status":"ok","profile": (cfg.get("env") or {}).get("profile")})
        register_version("bootstrap","0.1.0",{"status":"success"})
        return {"ok": True, "reports": {
            "resolve_config": s1["rendered"]["report"],
            "prepare_env": s2["rendered"]["report"],
            "generate_catalogs": s3["rendered"]["report"],
            "materialize_templates": s4["rendered"]["report"],
            "wire_integrations": s5["rendered"]["report"],
            "execute_plan": s6["rendered"]["report"],
            "finalize": s7["rendered"]["report"]
        }}
    except Exception as e:
        if "onfailure" in hooks:
            _L("hooks.hook_onfailure_bootstrap","hook_onfailure_bootstrap")({"agent": agent,"error": str(e)})
        log_event({"ident":"bootstrap_summary","status":"failed","error":str(e)})
        register_version("bootstrap","0.1.0",{"status":"failure","error": str(e)})
        return {"ok": False, "error": str(e)}
PY

