/**
 * Renderise du contenu JSON dans les .lns-section-section (1 fonction = 1 fichier)
 * Format attendu:
 * { "sections": [ { "ident":"sec_1", "title":{"FR":"..."}, "text":{"FR":"..."}, "badge":"..." }, ... ] }
 */
async function renderSections(contentUrl){
  try{
    const res = await fetch(contentUrl,{cache:"no-store"});
    const data = await res.json();
    const map = new Map((data.sections||[]).map(s => [s.ident, s]));
    document.querySelectorAll(".lns-section-section").forEach(sec=>{
      const ident = (sec.getAttribute("data-ident")||"").trim();
      const slot  = sec.querySelector(".lns-content");
      if(!slot) return;
      const s = map.get(ident);
      if(!s){ slot.innerHTML = "<p class='section-text'>[vide]</p>"; return; }
      const title = (s.title && (s.title.FR || s.title.en)) || ident;
      const text  = (s.text  && (s.text.FR  || s.text.en )) || "";
      const badge = s.badge ? `<div class="badge">${s.badge}</div>` : "";
      slot.innerHTML = `${badge}<h2 class="section-title">${title}</h2><p class="section-text">${text}</p>`;
    });
    console.log("[renderSections] ok");
  }catch(e){
    console.error("[renderSections] error", e);
    document.querySelectorAll(".lns-content").forEach(el=>{ el.innerHTML = "<p class='section-text'>[erreur de chargement]</p>"; });
  }
}
"""))

