# howto : from bootstrap.prerender_site_get import get_step
import json as _json

def _read(p):
    try:
        with open(p, "r", encoding="utf-8") as f:
            return f.read()
    except Exception:
        return None

def get_step(vectors):
    cfg = vectors.get("config") or {}
    site = vectors.get("site") or cfg.get("site") or {}
    env = cfg.get("env") or {}
    out_dir = (env.get("site_root") or "projects/agence_site")
    base_url = (site.get("base_url") or cfg.get("base_url") or "http://localhost:8001/").rstrip("/") + "/"

    # Résolution favicon
    icons = (site.get("head") or {}).get("icons") or {}
    favicon_svg = None

    if isinstance(icons, dict):
        # 1) inline SVG
        svg_inline = icons.get("svg")
        if isinstance(svg_inline, str) and "<svg" in svg_inline:
            favicon_svg = svg_inline

        # 2) chemin fichier
        if favicon_svg is None and icons.get("path"):
            t = _read(icons["path"])
            if t and "<svg" in t:
                favicon_svg = t

        # 3) héritage agence
        if favicon_svg is None and icons.get("inherit") == "agency":
            try:
                ag = _json.load(open("samples/agency_identity.json","r",encoding="utf-8"))
                fav = ((ag.get("icons") or {}).get("favicon") or {})
                if fav.get("type") == "svg_ref" and fav.get("path"):
                    t = _read(fav["path"])
                    if t and "<svg" in t:
                        favicon_svg = t
            except Exception:
                pass

    return {"ok": True, "site": site, "out_dir": out_dir, "base_url": base_url, "agent": vectors.get("agent"), "favicon_svg": favicon_svg}
""")

