w("bootstrap/prerender_site_execute.py", """# description : EXECUTE prerender_site — rend HTML complet + robots + sitemap + favicon
# howto : from bootstrap.prerender_site_execute import execute_step
import os, html, json
from assets.write_favicon import write_favicon

def _esc(s): 
    return html.escape(s or "", quote=True)

def _meta(name, content):
    return f'<meta name="{_esc(name)}" content="{_esc(content)}"/>'

def _meta_prop(prop, content):
    return f'<meta property="{_esc(prop)}" content="{_esc(content)}"/>'

def execute_step(spec):
    site = spec.get("site") or {}
    out_dir = spec.get("out_dir") or "projects/agence_site"
    base_url = (spec.get("base_url") or "").rstrip("/") + "/"
    os.makedirs(out_dir, exist_ok=True)

    lang = (site.get("lang") or "fr").lower()
    head = site.get("head") or {}
    body = site.get("body") or {}

    # --- Head (SEO) depuis la fractale ---
    title = (head.get("title",{}) or {}).get("FR") or head.get("title") or "Sans titre"
    if isinstance(title, dict): title = title.get("FR") or next(iter(title.values()), "Sans titre")
    desc  = (head.get("description",{}) or {}).get("FR") or head.get("description") or ""
    if isinstance(desc, dict): desc = desc.get("FR") or next(iter(desc.values()), "")
    canonical = head.get("canonical") or base_url
    og = head.get("og") or {}
    twitter = head.get("twitter") or {}
    ld = head.get("jsonld") or {}

    head_parts = []
    head_parts.append(f"<title>{_esc(title)}</title>")
    head_parts.append('<meta charset="utf-8"/>')
    head_parts.append('<meta name="viewport" content="width=device-width,initial-scale=1"/>')
    if desc: head_parts.append(_meta("description", desc))
    if canonical: head_parts.append(f'<link rel="canonical" href="{_esc(canonical)}"/>')
    # Open Graph
    head_parts.append(_meta_prop("og:title", og.get("title") or title))
    if desc: head_parts.append(_meta_prop("og:description", desc))
    head_parts.append(_meta_prop("og:type", og.get("type") or "website"))
    head_parts.append(_meta_prop("og:url", og.get("url") or canonical))
    if og.get("image"): head_parts.append(_meta_prop("og:image", og.get("image")))
    # Twitter
    head_parts.append(_meta("twitter:card", twitter.get("card") or "summary_large_image"))
    head_parts.append(_meta("twitter:title", twitter.get("title") or title))
    if desc: head_parts.append(_meta("twitter:description", desc))
    if twitter.get("image"): head_parts.append(_meta("twitter:image", twitter.get("image")))
    # CSS principal si présent
    if os.path.exists(os.path.join(out_dir, "theme_owner.css")):
        head_parts.append('<link rel="stylesheet" href="./theme_owner.css"/>')

    # favicon via fractale (si présent)
    if spec.get("favicon_svg"):
        write_favicon(out_dir, spec["favicon_svg"])
        head_parts.append('<link rel="icon" href="./favicon.ico" sizes="any">')
        head_parts.append('<link rel="icon" href="./favicon.svg" type="image/svg+xml">')

    # JSON-LD (schema.org)
    if ld:
        head_parts.append('<script type="application/ld+json">'+json.dumps(ld, ensure_ascii=False)+'</script>')

    head_html = "\\n  ".join(head_parts)

    # --- Body : sections remplies depuis fractale ---
    sections = []
    for sec in (body.get("sections") or []):
        ident = sec.get("ident") or "section"
        title_sec = (sec.get("title",{}) or {}).get("FR") or sec.get("title") or ident
        if isinstance(title_sec, dict): title_sec = title_sec.get("FR") or next(iter(title_sec.values()), ident)
        text_sec  = (sec.get("text",{})  or {}).get("FR")  or sec.get("text")  or ""
        if isinstance(text_sec, dict): text_sec = text_sec.get("FR") or next(iter(text_sec.values()), "")
        badge     = sec.get("badge") or ""
        inner = ""
        if badge: inner += f'<div class="badge">{_esc(badge)}</div>'
        inner += f'<h2 class="section-title">{_esc(title_sec)}</h2>'
        if text_sec: inner += f'<p class="section-text">{_esc(text_sec)}</p>'
        content = f'<div class="lns-container"><div class="lns-content">{inner}</div></div>'
        sections.append(f'<section id="lns-{_esc(ident)}" class="lns-section-section" data-ident="{_esc(ident)}">{content}</section>')

    body_html = "\\n  ".join(sections) if sections else "<div class=\\"lns-content\\"><p>Page générée (prerender), aucun contenu.</p></div>"

    html_doc = f\"\"\"<!doctype html>
<html lang="{_esc(lang)}">
<head>
  {head_html}
</head>
<body>
  {body_html}
</body></html>
\"\"\".strip()

    # Écrit index.html
    idx = os.path.join(out_dir, "index.html")
    with open(idx, "w", encoding="utf-8") as f: f.write(html_doc)

    # Robots.txt
    robots = f"User-agent: *\\nAllow: /\\nSitemap: {base_url}sitemap.xml\\n"
    with open(os.path.join(out_dir, "robots.txt"), "w", encoding="utf-8") as f: f.write(robots)

    # Sitemap (routes issues des sections ident/path)
    urls = [base_url]
    for sec in (body.get("sections") or []):
        path = sec.get("path")
        if path:
            urls.append(base_url.rstrip("/") + "/" + path.lstrip("/"))
    site_xml = ['<?xml version="1.0" encoding="UTF-8"?>','<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">']
    for u in urls:
        site_xml.append(f"<url><loc>{_esc(u)}</loc></url>")
    site_xml.append("</urlset>")
    with open(os.path.join(out_dir, "sitemap.xml"), "w", encoding="utf-8") as f:
        f.write("\\n".join(site_xml))

    return {"ok": True, "out_dir": out_dir, "index": idx, "base_url": base_url}
""")

