import argparse, json
from importlib import import_module

def _L(m,f): return import_module(m).__dict__[f]

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--config", required=True)
    ap.add_argument("--agent", required=True)
    args = ap.parse_args()
    cfg = json.load(open(args.config,encoding="utf-8"))
    agent = json.load(open(args.agent,encoding="utf-8"))

    get = _L("bootstrap.prerender_site_get","get_step")
    exe = _L("bootstrap.prerender_site_execute","execute_step")

    spec = get({"config": cfg, "agent": agent})
    out  = exe(spec)
    print("[prerender_only] ok =", out.get("ok"))
    if out.get("ok"):
        print("[prerender_only] index:", out.get("index"))

if __name__ == "__main__": main()
""")

