w("assets/path_utils.py", textwrap.dedent(r"""
#!/usr/bin/env python3
import os

CANDIDATE_SUFFIXES = ["_files", "_fichiers", "_files2", "_assets", "_resources"]

def guess_local_assets_dirs(html_path: str):
    base = os.path.splitext(os.path.basename(html_path))[0]
    parent = os.path.dirname(html_path)
    out = []
    for suf in CANDIDATE_SUFFIXES:
        d = os.path.join(parent, f"{base}{suf}")
        if os.path.isdir(d): out.append(d)
    for name in os.listdir(parent or "."):
        p = os.path.join(parent, name)
        if os.path.isdir(p) and (name.endswith("_fichiers") or name.endswith("_files")) and base in name:
            if p not in out: out.append(p)
    return out

def is_probably_local(href: str) -> bool:
    if not href: return False
    if href.startswith(("http://","https://","data:")): return False
    return True

def resolve_local_asset(html_path: str, href: str):
    direct = os.path.join(os.path.dirname(html_path), href.lstrip("./"))
    if os.path.isfile(direct):
        return direct
    for d in guess_local_assets_dirs(html_path):
        p = os.path.join(d, href.lstrip("./"))
        if os.path.isfile(p): return p
        p2 = os.path.join(d, os.path.basename(href))
        if os.path.isfile(p2): return p2
    return None
"""))

