#!/usr/bin/env python3
import urllib.request, os
def download_file(url: str, out_path: str, timeout: int = 30):
    os.makedirs(os.path.dirname(out_path), exist_ok=True)
    req = urllib.request.Request(url, headers={"User-Agent":"Mozilla/5.0 (clone_from_html)"})
    with urllib.request.urlopen(req, timeout=timeout) as r, open(out_path, "wb") as f:
