        if new!=s: body_html=body_html.replace(s,"./"+new)
        srcset_map.append({"from":s,"to":new})

    log_jsonl(reports, {"ident":"clone_from_html","phase":"IMAGES","imgs":img_map,"srcsets":srcset_map,"ts":now_iso()})

    # dict + manifest
    site_dict={
