#!/usr/bin/env python3
# description : EXECUTE — télécharge et parse chaque page (head/body → blocks)
# howto : from extract.pages_execute import pages_execute
import os, re, json, html, socket
from urllib.parse import urlparse, urljoin, urldefrag
from urllib.request import Request, urlopen
from urllib.error import URLError, HTTPError
from html.parser import HTMLParser

def pages_execute(get_out):
    spec = get_out["spec"]
    out_root = spec["out_root"]
    urls = spec["urls"]

    raw_dir = os.path.join(out_root, "raw")
    os.makedirs(raw_dir, exist_ok=True)

    # parse minimaliste
    class MiniParser(HTMLParser):
        def __init__(self):
            super().__init__()
            self.in_title=False; self.title=[]
            self.meta_desc=None
            self.styles=[]; self.icons=[]
            self.body_blocks=[]
            self.stack=[]
        def handle_starttag(self, tag, attrs):
            A=dict(attrs); t=tag.lower()
            if t=="title": self.in_title=True
            if t=="meta":
                n=A.get("name","").lower()
                if n=="description" and self.meta_desc is None:
                    self.meta_desc=A.get("content","")
            if t=="link":
                rel=(A.get("rel","") or A.get("rel",[]))
                if isinstance(rel, list): rel=" ".join(rel)
                rel=rel.lower()
                href=A.get("href")
                if href and "stylesheet" in rel: self.styles.append(href)
                if href and ("icon" in rel or "shortcut icon" in rel): self.icons.append(href)
            if t in ("h1","h2","h3","h4","h5","h6","p","a","img","ul","li"):
                self.stack.append(t)
                if t=="img":
                    self.body_blocks.append({"type":"img","src":A.get("src"),"alt": {"FR":A.get("alt","")}})
                elif t=="a":
                    self.body_blocks.append({"type":"a","href":A.get("href"),"text": {"FR":""}})
                elif t=="ul":
                    self.body_blocks.append({"type":"ul","items":[]})
                elif t=="li":
                    self.body_blocks.append({"type":"li","text":{"FR":""}})
        def handle_endtag(self, tag):
            t=tag.lower()
            if t=="title": self.in_title=False
            if self.stack and self.stack[-1]==t: self.stack.pop()
        def handle_data(self, data):
            d=data.strip()
            if not d: return
            if self.in_title: self.title.append(d)
            # attache le texte au dernier block textuel ouvert
            if self.stack:
                cur=self.stack[-1]
                for i in range(len(self.body_blocks)-1,-1,-1):
                    b=self.body_blocks[i]
                    if cur in ("h1","h2","h3","h4","h5","h6"):
                        if b.get("type")==cur:
                            b.setdefault("text",{"FR":""})
                            b["text"]["FR"] += ("" if b["text"]["FR"]=="" else " ")+d
                            return
                    if cur=="p" and b.get("type")=="p":
                        b.setdefault("text",{"FR":""})
                        b["text"]["FR"] += ("" if b["text"]["FR"]=="" else " ")+d
                        return
                    if cur=="a" and b.get("type")=="a" and "text" in b:
                        b["text"]["FR"] += ("" if b["text"]["FR"]=="" else " ")+d
                        return
                    if cur=="li" and b.get("type")=="li":
                        b["text"]["FR"] += ("" if b["text"]["FR"]=="" else " ")+d
                        return
                # si pas trouvé, on crée un block du type courant
                if cur in ("h1","h2","h3","h4","h5","h6","p"):
                    self.body_blocks.append({"type":cur,"text":{"FR":d}})

    def _ua_request(url):
        return Request(url, headers={"User-Agent":"byGPT/ExtractPages/0.1"})

    def _fetch_html(url):
        try:
            with urlopen(_ua_request(url), timeout=15) as r:
                ctype=r.headers.get("Content-Type","")
                enc="utf-8"
                if "charset=" in ctype:
                    enc=ctype.split("charset=")[-1].split(";")[0].strip()
                return r.read().decode(enc, "ignore")
        except (HTTPError, URLError, socket.timeout) as e:
            return None

    def _slugify(u):
        pu=urlparse(u)
        path=pu.path or "/"
        if path=="/": return "home"
        s=re.sub(r"[^a-zA-Z0-9/_-]+","-",path).strip("-").strip("/")
        if not s: s="page"
        return s.replace("/","_")

    pages=[]
    for u in urls:
        html=_fetch_html(u)
        ident=_slugify(u)
        raw_path=os.path.join(raw_dir, f"{ident}.html")
        if html is not None:
            open(raw_path,"w",encoding="utf-8").write(html)
            p=MiniParser(); p.feed(html)
            title=(" ".join(p.title) or "").strip()
            head={
                "title": {"FR": title} if title else None,
                "meta": {"description": {"FR": p.meta_desc}} if p.meta_desc else {}
            }
            # body: compacter li dans ul (items)
            compact=[]
            stack=[]
            for b in p.body_blocks:
                if b["type"]=="ul":
                    stack.append({"type":"ul","items":[]}); compact.append(stack[-1])
                elif b["type"]=="li":
                    if stack and stack[-1]["type"]=="ul":
                        stack[-1]["items"].append(b.get("text") or {"FR":""})
                    else:
                        compact.append({"type":"p","text":b.get("text") or {"FR":""}})
                else:
                    compact.append(b)
            pages.append({
                "identity": {"ident": ident, "url": u},
                "definitions": {
                    "head": head,
                    "resources": {
                        "styles": p.styles,
                        "icons": p.icons
                    },
                    "body": [b for b in compact if b]
                }
            })
        else:
            pages.append({
                "identity": {"ident": ident, "url": u},
                "definitions": {"head": {}, "resources": {"styles": [], "icons": []}, "body": []},
                "error": f"fetch_failed:{u}"
            })

    return {"ok": True, "pages": pages, "out_root": out_root}
PY

