#!/usr/bin/env python3
# description : Télécharge les images des pages et réécrit les src en local
# howto : from assets.fetch_images import fetch_images
import os, json, hashlib, urllib.request, urllib.parse

def fetch_images(out_root):
    pages_dir=os.path.join(out_root,"catalogs","pages")
    if not os.path.isdir(pages_dir):
        return {"ok": False, "diagnostics":["catalogs/pages introuvable"]}

    img_dir=os.path.join(out_root,"assets","img"); os.makedirs(img_dir, exist_ok=True)
    pages=os.listdir(pages_dir); saved=0; failed=0

    def _fetch(u):
        try:
            with urllib.request.urlopen(u, timeout=15) as r:
                return r.read()
        except Exception:
            return None

    for fname in pages:
        if not fname.endswith(".json"): continue
        pth=os.path.join(pages_dir,fname)
        page=json.load(open(pth,"r",encoding="utf-8"))
        body=((page.get("definitions") or {}).get("body") or [])
        changed=False
        for b in body:
            if b.get("type")=="img":
                src=b.get("src")
                if not src: continue
                if not urllib.parse.urlparse(src).scheme:
                    # déjà relatif → on laisse
                    continue
                data=_fetch(src)
                if data is None:
                    failed+=1; continue
                h=hashlib.sha1(data).hexdigest()[:12]
                ext=os.path.splitext(urllib.parse.urlparse(src).path)[1] or ".bin"
                local=f"assets/img/{h}{ext}"
                open(os.path.join(out_root,local),"wb").write(data)
                b["src"]=local
                saved+=1; changed=True
        if changed:
            json.dump(page, open(pth,"w",encoding="utf-8"), ensure_ascii=False, indent=2)

    return {"ok": True, "saved": saved, "failed": failed}
PY

