import os, json, re, urllib.request, urllib.parse

def rewrite_css(out_root):
    site_path=os.path.join(out_root,"catalogs","site.json")
    if not os.path.isfile(site_path): 
        return {"ok": False, "diagnostics":["site.json introuvable"]}
    site=json.load(open(site_path,"r",encoding="utf-8"))

    styles=((site.get("definitions") or {}).get("head") or {}).get("styles") or []
    hrefs=[s.get("href") for s in styles if s.get("href")]
    if not hrefs:
        # tente avec la première page
        pages_dir=os.path.join(out_root,"catalogs","pages")
        if os.path.isdir(pages_dir):
            for f in os.listdir(pages_dir):
                if not f.endswith(".json"): continue
                page=json.load(open(os.path.join(pages_dir,f),"r",encoding="utf-8"))
                rs=((page.get("definitions") or {}).get("resources") or {}).get("styles") or []
                hrefs.extend(rs)
                if hrefs: break

    css_dir=os.path.join(out_root,"assets","css"); os.makedirs(css_dir, exist_ok=True)
    scss_dir=os.path.join(out_root,"assets","scss"); os.makedirs(scss_dir, exist_ok=True)
    out_css=os.path.join(css_dir,"theme_owner.css")
    out_scss=os.path.join(scss_dir,"theme_owner.scss")

    combined=[]
    for href in hrefs:
        try:
            with urllib.request.urlopen(href, timeout=15) as r:
                combined.append(r.read().decode("utf-8","ignore"))
        except Exception:
            continue

    if not combined:
        combined.append("/* stylesheet placeholder (aucune CSS distante récupérée) */")

    open(out_css,"w",encoding="utf-8").write("\n\n/* --- next file --- */\n\n".join(combined))
    open(out_scss,"w",encoding="utf-8").write("// SCSS d'entrée, issu du CSS cloné\n@import \"../css/theme_owner.css\";\n")

    # met à jour la ref dans site.json
    head=site.setdefault("definitions",{}).setdefault("head",{})
    head["styles"]=[{"href":"assets/css/theme_owner.css"}]
    json.dump(site, open(site_path,"w",encoding="utf-8"), ensure_ascii=False, indent=2)

    return {"ok": True, "css":"assets/css/theme_owner.css", "scss":"assets/scss/theme_owner.scss"}
