#!/usr/bin/env python3
# description : Prérendu à partir des catalogues (site + pages) → deploy/ HTML complet
# howto : from regenerate.prerender_site import prerender_site
import os, json, shutil

def prerender_site(out_root):
    site_path=os.path.join(out_root,"catalogs","site.json")
    pages_dir=os.path.join(out_root,"catalogs","pages")
    if not os.path.isfile(site_path) or not os.path.isdir(pages_dir):
        return {"ok": False, "diagnostics":["catalogs incomplets"]}

    site=json.load(open(site_path,"r",encoding="utf-8"))
    deploy=os.path.join(out_root,"deploy"); os.makedirs(deploy, exist_ok=True)

    # copier assets → deploy/assets
    src_assets=os.path.join(out_root,"assets")
    dst_assets=os.path.join(deploy,"assets")
    if os.path.isdir(dst_assets): shutil.rmtree(dst_assets)
    if os.path.isdir(src_assets): shutil.copytree(src_assets, dst_assets)

    def _title_of(page):
        return (((page.get("definitions") or {}).get("head") or {}).get("title") or {}).get("FR") \
               or (((site.get("definitions") or {}).get("head") or {}).get("title") or {}).get("FR","")

    def _desc_of(page):
        md=(((page.get("definitions") or {}).get("head") or {}).get("meta") or {}).get("description")
        if isinstance(md, dict): return md.get("FR","")
        return ""

    def _favicon_href():
        fav=(((site.get("definitions") or {}).get("head") or {}).get("favicon") or {})
        return fav.get("href") or fav.get("ref") or "assets/icons/favicon.svg"

    def _css_href():
        styles=(((site.get("definitions") or {}).get("head") or {}).get("styles") or [])
        if styles: return styles[0].get("href","assets/css/theme_owner.css")
        return "assets/css/theme_owner.css"

    def _render_block(b):
        t=b.get("type")
        if t in ("h1","h2","h3","h4","h5","h6"):
            return f"<{t} class='lns-{t}'>{(b.get('text') or {}).get('FR','')}</{t}>"
        if t=="p":
            return f"<p class='lns-p'>{(b.get('text') or {}).get('FR','')}</p>"
        if t=="a":
            href=b.get("href") or "#"
            return f"<a href='{href}' class='lns-a'>{(b.get('text') or {}).get('FR','')}</a>"
        if t=="img":
            src=b.get("src") or ""
            alt=(b.get("alt") or {}).get("FR","")
            return f"<img src='/{src}' alt='{alt}' class='lns-img'/>"
        if t=="ul":
            items=b.get("items") or []
            lis="".join([f"<li>{(it or {}).get('FR','')}</li>" for it in items])
            return f"<ul class='lns-ul'>{lis}</ul>"
        return ""

    # charger toutes les pages
    pages=[]
    for f in os.listdir(pages_dir):
        if not f.endswith(".json"): continue
        pages.append(json.load(open(os.path.join(pages_dir,f),"r",encoding="utf-8")))
    # index.html pour home + sous-dossiers pour autres pages
    for p in pages:
        ident=(p.get("identity") or {}).get("ident","page")
        body=((p.get("definitions") or {}).get("body") or [])
        head_html=f"""<meta charset="utf-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>{_title_of(p)}</title>
<meta name="description" content="{_desc_of(p)}"/>
<link rel="icon" href="/{_favicon_href()}"/>
<link rel="stylesheet" href="/{_css_href()}"/>"""
        body_html="".join([_render_block(b) for b in body])
        html=f"<!doctype html><html lang='fr'><head>{head_html}</head><body>{body_html}</body></html>"

        if ident=="home":
            target=os.path.join(deploy,"index.html")
        else:
            d=os.path.join(deploy, ident); os.makedirs(d, exist_ok=True)
            target=os.path.join(d,"index.html")
        open(target,"w",encoding="utf-8").write(html)

    return {"ok": True, "deploy": deploy, "pages": len(pages)}
PY

