import argparse, json
from importlib import import_module
from log.log_event import log_event

def main():
    p=argparse.ArgumentParser()
    p.add_argument("--out-root", required=True)
    args=p.parse_args()

    before=import_module("hooks.hook_before_prerender").hook_before_prerender
    after =import_module("hooks.hook_after_prerender").hook_after_prerender
    fail  =import_module("hooks.hook_onfailure_prerender").hook_onfailure_prerender
    prer  =import_module("regenerate.prerender_site").prerender_site

    try:
        before({"out_root": args.out_root})
        r=prer(args.out_root)
        log_event({"kind":"step","step":"PRERENDER","method":"prerender","ok":r.get("ok"),"pages":r.get("pages")})
        after({"report":r})
        print("[prerender] ok =", r.get("ok"))
        print("[prerender] report:", json.dumps(r, ensure_ascii=False))
    except Exception as e:
        fail({"error": str(e), "out_root": args.out_root})
        print("[prerender] ok =", False)
        print("[prerender] error:", str(e))

if __name__=="__main__":
    main()
