#!/usr/bin/env python3
# description : Pipeline "une commande" — scrape_urls → extract_pages → fetch_assets → prerender → serve
# howto :
#   PYTHONPATH=$(pwd) python3 -m entrypoints.run_clone_and_serve \
#     --start-url http://localhost:8001 --out projects/site_clone --max-pages 100 --max-depth 5 --port 8010
import argparse, os, sys
from importlib import import_module
from log.log_event import log_event

def _call(modname, arglist):
    # Exécute main() d'un module qui parse argparse, en simulant sys.argv
    m=import_module(modname)
    old=sys.argv[:]
    sys.argv=[modname]+arglist
    try:
        m.main()
    finally:
        sys.argv=old

def main():
    p=argparse.ArgumentParser()
    p.add_argument("--start-url", required=True)
    p.add_argument("--out", required=True)
    p.add_argument("--max-pages", type=int, default=100)
    p.add_argument("--max-depth", type=int, default=5)
    p.add_argument("--port", type=int, default=8010)
    args=p.parse_args()

    log_event({"kind":"phase","stage":"clone_and_serve","status":"start","url":args.start_url,"out":args.out})

    # 1) scrape_urls → urls.json
    _call("entrypoints.scrape_urls", ["--start-url", args.start_url, "--max-pages", str(args.max_pages), "--max-depth", str(args.max_depth), "--out", args.out])

    # 2) extract_pages → catalogs/site.json + catalogs/pages/*.json
    _call("entrypoints.extract_pages", ["--out-root", args.out])

    # 3) fetch_assets → favicon/images/css/scss
    _call("entrypoints.fetch_assets", ["--out-root", args.out])

    # 4) prerender → deploy/
    _call("entrypoints.prerender_from_catalogs", ["--out-root", args.out])

    # 5) serve
    serve=import_module("webserver.start_http_server").start_http_server
    site_root=os.path.join(args.out,"deploy"); os.makedirs(site_root, exist_ok=True)
    print(f"[clone_and_serve] prêt sur http://localhost:{args.port} (root={site_root})")
    serve(site_root, args.port)

if __name__=="__main__":
    main()
