#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Emet des fichiers CSS a partir des catalogues:
- catalogs/style_normalized.json  (entrees normalisees avec page/breakpoint/selector/properties)
- catalogs/breakpoint.json        (map des breakpoints -> media condition) [optionnel]

Sorties:
- projects/<site_ident>/deploy/assets/css/style.global.css
- projects/<site_ident>/deploy/assets/css/style.<page>.css
- projects/<site_ident>/deploy/assets/css/style.<page>.<bp>.css
- projects/<site_ident>/deploy/assets/css/css_emit_manifest.json
- reports/css_emit.jsonl (journal JSONL)
"""

import json, hashlib, os, sys
from pathlib import Path
from datetime import datetime, timezone
from collections import defaultdict

class CSSEmitter:
    def __init__(self, site_ident=None, out_root=None):
        self.base_dir = Path(".")
        self.catalogs_dir = self.base_dir / "catalogs"
        self.reports_dir  = self.base_dir / "reports"
        self.site_ident   = site_ident
        self.out_root     = Path(out_root) if out_root else None
        self.log_entries  = []
        self.emitted_files = []
        self.policy = {
            "emit_global_css": True,
            "emit_page_css": True,
            "emit_per_breakpoint": True,
            "deterministic_sort": True,
            "ensure_page_field": True
        }

    def log(self, phase, details):
        entry = {
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "phase": phase,
            "details": details
        }
        self.log_entries.append(entry)
        # echo console court
        if isinstance(details, dict):
            summary = ", ".join(f"{k}={v}" for k, v in details.items())
        else:
            summary = str(details)
        print(f"[emit] {phase}: {summary}")

    def load_catalog(self, filename):
        p = self.catalogs_dir / filename
        if not p.exists():
            return {}
        with p.open("r", encoding="utf-8") as f:
            return json.load(f)

    def get_site_ident(self):
        if self.site_ident:
            return self.site_ident
        sites = self.load_catalog("site.json")
        if isinstance(sites, dict) and sites.get("sites"):
            self.site_ident = sites["sites"][-1].get("ident")
        return self.site_ident

    def normalize_entry(self, e):
        e = dict(e or {})
        if self.policy["ensure_page_field"]:
            if not e.get("page"):
                e["page"] = "global"
        if not e.get("breakpoint"):
            e["breakpoint"] = "bp_all"
        if "important" not in e:
            e["important"] = False
        if "specificity" not in e:
            e["specificity"] = 0
        if "order" not in e:
            e["order"] = 0
        if "origin" not in e:
            e["origin"] = "sheet"
        if "properties" not in e or not isinstance(e["properties"], dict):
            e["properties"] = {}
        if "selector" not in e:
            e["selector"] = ""
        return e

    def sort_key(self, e):
        origin_weights = {"sheet": 0, "block": 1, "inline": 2}
        return (
            -int(bool(e.get("important"))),
            -int(e.get("specificity", 0)),
            origin_weights.get(e.get("origin", "sheet"), 0),
            int(e.get("order", 0))
        )

    def format_rule(self, selector, properties):
        if not selector or not properties:
            return ""
        lines = [f"{selector} {{\n"]
        for k in sorted(properties.keys()):
            v = properties[k]
            lines.append(f"  {k}: {v};\n")
        lines.append("}\n\n")
        return "".join(lines)

    def write_css(self, path, rules):
        # tri
        if self.policy["deterministic_sort"]:
            rules = sorted(rules, key=self.sort_key)
        # contenu
        buf = []
        for r in rules:
            buf.append(self.format_rule(r.get("selector",""), r.get("properties", {})))
        content = "".join(buf)
        # write
        path.parent.mkdir(parents=True, exist_ok=True)
        with path.open("w", encoding="utf-8") as f:
            f.write(content)
        sha256 = hashlib.sha256(content.encode("utf-8")).hexdigest()
        size = len(content.encode("utf-8"))
        return sha256, size

    def emit_all(self, entries, bps):
        self.log("emit_start", {"total_entries": len(entries)})
        grouped = defaultdict(lambda: defaultdict(list))
        for e in entries:
            page = e.get("page","global")
            bp   = e.get("breakpoint","bp_all")
            grouped[page][bp].append(e)

        # global
        if self.policy["emit_global_css"]:
            all_rules = []
            for page_rules in grouped.values():
                for bp_rules in page_rules.values():
                    all_rules.extend(bp_rules)
            if all_rules:
                p = self.out_root / "style.global.css"
                sha, sz = self.write_css(p, all_rules)
                self.emitted_files.append({
                    "type":"global","page":"global","bp":"bp_all",
                    "file": p.name, "sha256": sha, "size": sz
                })
                self.log("file_emitted", {"file": p.name, "size": sz})

        # par page
        if self.policy["emit_page_css"]:
            for page, bp_rules in grouped.items():
                if page == "global":
                    continue
                rules = []
                for rr in bp_rules.values():
                    rules.extend(rr)
                if rules:
                    p = self.out_root / f"style.{page}.css"
                    sha, sz = self.write_css(p, rules)
                    self.emitted_files.append({
                        "type":"page","page":page,"bp":"bp_all",
                        "file": p.name, "sha256": sha, "size": sz
                    })
                    self.log("file_emitted", {"file": p.name, "size": sz})

        # par breakpoint
        if self.policy["emit_per_breakpoint"]:
            bp_map = {}
            if isinstance(bps, dict) and bps.get("breakpoints"):
                # bps["breakpoints"] peut etre un dict {bp_id: {condition:..}}
                if isinstance(bps["breakpoints"], dict):
                    bp_map = bps["breakpoints"]
                # ou une liste [{"ident":..,"condition":..}]
                elif isinstance(bps["breakpoints"], list):
                    for it in bps["breakpoints"]:
                        bp_map[it.get("ident")] = {"condition": it.get("condition")}

            for page, bp_rules in grouped.items():
                for bp, rules in bp_rules.items():
                    if bp == "bp_all" or not rules:
                        continue
                    p = self.out_root / f"style.{page}.{bp}.css"
                    sha, sz = self.write_css(p, rules)
                    entry = {
                        "type":"page_bp","page":page,"bp":bp,
                        "file": p.name, "sha256": sha, "size": sz
                    }
                    if bp in bp_map:
                        entry["media"] = bp_map[bp].get("condition")
                    self.emitted_files.append(entry)
                    self.log("file_emitted", {"file": p.name, "size": sz, "bp": bp})

        return len(self.emitted_files)

    def create_manifest(self):
        pages = sorted({e["page"] for e in self.emitted_files})
        bps   = sorted({e["bp"] for e in self.emitted_files})
        manifest = {
            "site_ident": self.site_ident,
            "generated_at": datetime.now(timezone.utc).isoformat(),
            "files": self.emitted_files,
            "stats": {
                "files_total": len(self.emitted_files),
                "pages_emitted": len(pages),
                "bps_emitted": len(bps)
            }
        }
        out = self.out_root / "css_emit_manifest.json"
        with out.open("w", encoding="utf-8") as f:
            json.dump(manifest, f, ensure_ascii=False, indent=2)
        return out

    def run(self):
        print("\n[emit] CSS emission")
        self.site_ident = self.get_site_ident()
        if not self.site_ident:
            self.log("error", {"message":"site_ident introuvable (passe --site-ident)"})
            return
        if not self.out_root:
            self.out_root = self.base_dir / "projects" / self.site_ident / "deploy" / "assets" / "css"
        self.out_root.mkdir(parents=True, exist_ok=True)

        self.log("config", {"site_ident": self.site_ident, "out_root": str(self.out_root)})

        normalized = self.load_catalog("style_normalized.json")
        if not normalized or not normalized.get("entries"):
            self.log("error", {"message":"catalogs/style_normalized.json manquant ou vide"})
            return
        breakpoints = self.load_catalog("breakpoint.json")

        # normaliser
        entries = [self.normalize_entry(e) for e in (normalized.get("entries") or [])]
        self.log("normalized", {"entries": len(entries)})

        # emettre
        files_count = self.emit_all(entries, breakpoints)

        # manifest + logs
        manifest_path = self.create_manifest()
        self.reports_dir.mkdir(exist_ok=True)
        log_path = self.reports_dir / "css_emit.jsonl"
        with log_path.open("w", encoding="utf-8") as f:
            for e in self.log_entries:
                f.write(json.dumps(e, ensure_ascii=False) + "\n")

        self.log("complete", {
            "files_emitted": files_count,
            "manifest": str(manifest_path),
            "log": str(log_path)
        })

def main():
    import argparse
    p = argparse.ArgumentParser(description="Emet les CSS a partir des catalogues normalises.")
    p.add_argument("--site-ident", default=None, help="Identifiant du site (ex: www_myhealthprac_com)")
    p.add_argument("--out-root", default=None, help="Dossier de sortie des CSS")
    args = p.parse_args()

    CSSEmitter(site_ident=args.site_ident, out_root=args.out_root).run()

if __name__ == "__main__":
    main()
