    const x = Math.min(Math.max(e.clientX, 160), w - 160); // bornes min/max
    const pct = (x / w) * 100;
    root.style.setProperty('--split', pct.toFixed(2) + '%');
  });

  // Detect iframe block (CSP / XFO): si en 1500ms rien ne s’est affiché, on montre l’overlay
  const orig = document.getElementById('orig');
  const overlay = document.getElementById('origOverlay');
  let loaded = false;
  // onload ne se déclenche pas si bloqué par XFO, donc on timeout
  setTimeout(() => { if (!loaded) overlay.classList.add('show'); }, 1500);
  orig.addEventListener('load', () => { loaded = true; overlay.classList.remove('show'); });

  // Snapshot local optionnel: si projects/<site>/deploy/original.html existe, on peut l’utiliser
  // Ici on tente ./original.html (mets ce snapshot à côté de index.html si tu en as un)
  document.getElementById('useSnapshot').addEventListener('click', async () => {
    try {
      const res = await fetch('./original.html', {cache:'no-store'});
      if (!res.ok) throw new Error('404');
      overlay.classList.remove('show');
      orig.src = './original.html';
    } catch (_) {
      alert("Aucun snapshot local trouvé (./original.html). Place un snapshot et réessaie.");
    }
  });
})();
</script>
</body>
</html>

Pourquoi l’original ne s’affiche pas ?
Beaucoup de sites refusent l’embarquement en <iframe> via des en-têtes de sécurité. Ton clone local, lui, se charge sans restriction — d’où l’aspect “deux blocs” avec le gauche vide.
Pour une vraie comparaison visuelle


Option A (recommandée) : génère un snapshot HTML local de l’original (via ton pipeline de scraping / prérendu) et enregistre-le comme projects/<site>/deploy/original.html, puis clique “Charger snapshot local”.


Option B : ouvre l’original dans un nouvel onglet (bouton prévu) et compare manuellement.


Option C (avancé) : passer par un proxy qui supprime ces en-têtes (souvent contraire aux CGU — à éviter).


Une fois le snapshot local ajouté, la comparaison sera 1:1, en pleine largeur, et tu peux ajuster le séparateur central pour inspecter finement.
